#ifndef _SOFA_PBRPC_SCOPED_LOCKER_H_
#define _SOFA_PBRPC_SCOPED_LOCKER_H_

namespace sofa {
namespace pbrpc {

template <typename LockType>
class ScopedLocker
{
public:
    explicit ScopedLocker(LockType& lock)
        : _lock(&lock)
    {
        _lock->lock();
    }

    explicit ScopedLocker(LockType* lock)
        : _lock(lock)
    {
        _lock->lock();
    }

    ~ScopedLocker()
    {
        _lock->unlock();
    }

private:
    LockType* _lock;
}; // class ScopedLocker

} // namespace pbrpc
} // namespace sofa

#endif // _SOFA_PBRPC_SCOPED_LOCKER_H_

